                                                 -->                                    -->                                                                            -->                                -->                                                            -->                                -->                                                            -->                -->                                            Supprimer                                                                                      Ajouter une ligne                                                          Échéance : Conformément à nos nos accords, le délai de paiement            pour cette facture est de {{ deadline }} jours            à compter de la date d\\'émission.                                      Enregistrer                    '\n    var COMPONENTS = [{'name': 'AddClientComponent', 'selector': 'app-add-client'},{'name': 'AddComponent', 'selector': 'app-add'},{'name': 'AddInstructorComponent', 'selector': 'app-add-instructor'},{'name': 'AddInvoiceDialogContentComponent', 'selector': 'app-add-invoice-dialog-content'},{'name': 'AddTrainingComponent', 'selector': 'app-add-training'},{'name': 'AddVendorComponent', 'selector': 'app-add-vendor'},{'name': 'AgendaComponent', 'selector': 'app-agenda'},{'name': 'AppClientDialogContentComponent', 'selector': 'app-dialog-content'},{'name': 'AppComponent', 'selector': 'app-root'},{'name': 'AppInstructorDialogContentComponent', 'selector': 'app-dialog-content'},{'name': 'AppSearchDialogComponent', 'selector': 'search-dialog'},{'name': 'AppTrainingDialogContentComponent', 'selector': 'app-dialog-content'},{'name': 'AppVendorDialogContentComponent', 'selector': 'app-vendor-dialog-content'},{'name': 'BlankComponent', 'selector': 'app-blank'},{'name': 'BrandingComponent', 'selector': 'app-branding'},{'name': 'BreadcrumbComponent', 'selector': 'app-breadcrumb'},{'name': 'ClientComponent', 'selector': 'app-client'},{'name': 'ClientTrainingC